INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (114, 104, 79.4, 86, 68, 80, 84, 75, 75, 'Mid-engine aluminum-steel composite body - excellent rigidity, lightweight panels, race-derived structural design', 'Sports car NVH - flat-4 turbo is audible (some say sounds like a Subaru), road noise from mid-engine layout, not GT-grade', 'Porsche quality in the mid-engine format - good leather, Alcantara options, excellent sport seats, driver-focused cockpit', 'Porsche paint quality is consistently excellent - deep metallics, smooth coverage, consistent clear coats', 'PCM with Apple CarPlay is modern and functional - screen quality holds up, physical buttons for key functions', 'Premium materials age well with care - Alcantara can absorb oils on steering wheel, leather seats develop character', 'Porsche mid-engine build quality at its best - the 718 benefits from continuous evolution of the 981 platform', '982 platform (evolved from 981)', 'Porsche Zuffenhausen (Stuttgart)', 'spot weld + adhesive bonding', 3.3, 'hydraulic', 'tinted', 'available full leather', 'aluminum/optional carbon', 6, 'good', 'sample');

