INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (115, 114, 67.0, 74, 68, 72, 75, 52, 55, 'C5 PL45+ platform with Avant body - adequate rigidity, galvanized steel, wide-body fender flares unique to RS6', 'Not luxury-quiet - twin-turbo V8 dominates the soundscape, Avant body allows some boom, acceptable for super-sedan of era', 'Audi RS-quality for early 2000s - Recaro seats excellent, some carbon fiber trim, but 20-year-old materials showing age', 'Audi galvanization is solid - bodies hold up well, RS6-specific paint colors are deep and consistent', '20+ year old Audi electronics are the achilles heel - instrument cluster pixels, comfort module failures, CAN bus gremlins', 'Dashboard plastics crack, leather seats show 20+ years of wear, headliner sags - cosmetic age is the reality of C5 ownership', 'Period-flagship Audi build quality that hasn''t aged gracefully - the body is durable, interior and electronics are the weak points', 'C5 PL45+ platform (enhanced B5)', 'Audi Neckarsulm (Germany)', 'spot weld + laser weld', 4.5, 'solid hydraulic', 'tinted', 'recaro leather/alcantara', 'carbon fiber trim', 4, 'below_average', 'sample');
